ALTER TABLE "role_permission" ALTER COLUMN "permission" SET DATA TYPE text;--> statement-breakpoint
ALTER TABLE "user_permission" ALTER COLUMN "permission" SET DATA TYPE text;--> statement-breakpoint
-- SPEC-253: collapse the 10 legacy per-section commerce.*.editOwn permissions
-- into the single consolidated commerce.editOwn. Runs while the column is still
-- `text` (the legacy values would be rejected by the new enum during the cast
-- below, and the new value does not yet exist in the old enum). This block makes
-- the migration work on environments where the seed never runs (staging/prod):
-- 1. Re-grant commerce.editOwn to every ROLE that held any legacy per-section perm.
INSERT INTO "role_permission" ("role", "permission")
SELECT DISTINCT "role", 'commerce.editOwn'
FROM "role_permission"
WHERE "permission" LIKE 'commerce.%.editOwn'
ON CONFLICT DO NOTHING;--> statement-breakpoint
-- 2. Drop the legacy per-section grants from both permission tables. user_permission
-- overrides are dropped (not re-granted): the consolidated role grant governs now.
DELETE FROM "role_permission" WHERE "permission" LIKE 'commerce.%.editOwn';--> statement-breakpoint
DELETE FROM "user_permission" WHERE "permission" LIKE 'commerce.%.editOwn';--> statement-breakpoint
DROP TYPE "public"."permission_enum";--> statement-breakpoint
